using System.Data;
using Dapper;
using Valora.Application.Contracts;
namespace Valora.Infrastructure.Repositories;
public sealed class CertificateRepository(IDbConnectionFactory f):ICertificateRepository{ public async Task<dynamic?> GetByResponseAsync(Guid responseId){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT * FROM valorapesquisa.certificates WHERE response_id=@responseId",new{responseId});} public async Task CreateMetadataAsync(Guid responseId,string validationCode,string status){using var c=f.Create(); await c.ExecuteAsync("INSERT INTO valorapesquisa.certificates(response_id,certificate_code,issuer_name,status) VALUES (@responseId,@validationCode,'Valora Pulse',@status) ON CONFLICT (certificate_code) DO UPDATE SET updated_at=now()",new{responseId,validationCode,status});} public async Task CreateMetadataAsync(Guid organizationId,Guid responseId,string code,string? participantName,string issuerName,string surveyName,string maturityLabel,IDbTransaction tx){await tx.Connection!.ExecuteAsync("INSERT INTO valorapesquisa.certificates(organization_id,response_id,certificate_code,participant_name,issuer_name,survey_name,maturity_label,status) VALUES (@organizationId,@responseId,@code,@participantName,@issuerName,@surveyName,@maturityLabel,'metadata-ready')",new{organizationId,responseId,code,participantName,issuerName,surveyName,maturityLabel},tx);}}
